import rclpy
from rclpy.node import Node
from std_msgs.msg import String
import serial
import time
import numpy as np

from custom_interfaces.srv import CommandResponse


### This is really just a guidance block
# takes messages from `surface_data` topic which are formatted as `STICKS f/r l/r v`
# number inputs are -1 to 1

class MoveMotors(Node):
    def __init__(self):
        ### Configuration ###
        self.guidance_function = self.manual

        ### Surface data listener setup ###
        super().__init__('move_motors')
        self.get_logger().info('MoveMotors node has been started.')   
        self.subscription = self.create_subscription(
            String,
            'surface_data',
            self.listener_callback,
            10)
        
        ### Microcontroller service setup ###
        self.cli = self.create_client(CommandResponse, 'talk_to_micro')
        while not self.cli.wait_for_service(timeout_sec=1.0):
            self.get_logger().info('talk_to_micro service not available, waiting again...')

        ### Command sender setup ###
        # timer_period = 1/50  # seconds
        # self.timer = self.create_timer(timer_period, self.send_motor_commands)
        
        self.request = CommandResponse.Request()


    def manual(self, stick_commands):
        # Combines stick commands into motor commands
        output_commands = np.array([0, 0, 0], dtype=float)
        
        output_commands[0] = np.clip(stick_commands[0] - stick_commands[1], a_min=-1, a_max=1) 
        output_commands[1] = np.clip(stick_commands[0] + stick_commands[1], a_min=-1, a_max=1) 
        output_commands[2] = stick_commands[2] # vertical stick directly controls vertical thruster

        output_commands = ((output_commands+1) * 126).astype(int) 
        self.send_motor_commands(output_commands)

    def listener_callback(self, msg):
        self.get_logger().info(f'Got raw message: "{msg.data}"')
        command = msg.data
        if not command.startswith("STICKS "):
            return
        command = command.strip("STICKS ")
        command = list(map(float, command.split()))

        self.get_logger().info(f'Received motor command: "{command}"')
        self.guidance_function(command)
    
    def send_motor_commands(self, motor_commands):
        self.request.command = f'1 {motor_commands[0]} {motor_commands[1]} {motor_commands[2]}'
        self.request.expect_response = False
        _ = self.cli.call_async(self.request)
        # self.get_logger().info(f'Sent motor command: "{motor_commands}"')

def main(args=None):
    rclpy.init(args=args)
    node = MoveMotors()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    finally:
        rclpy.shutdown()


if __name__ == '__main__':
    main()